for (const item of $input.all()) {
  // نتحقق من وجود الملف الصوتي في خاصية data
  if (item.binary && item.binary.data) {
    // نقوم بتغيير اسم الملف والامتداد إلى ogg
    item.binary.data.fileName = 'student_voice.ogg';
    item.binary.data.mimeType = 'audio/ogg';
  }
}
return $input.all();

const item = $input.first();

const oldMetadata = $input.first().json.metadata || {};

return [
  {
    json: {
      metadata: {
        ...oldMetadata,
        domain: $('If1').first().json.body.data.domain,
        unit: $('If1').first().json.body.data.unit,
        title:$('If1').first().json.body.data.title ,
        keywords:$('If1').first().json.body.data.keywords ? $('If1').first().json.body.data.keywords.split(/[,،]/).map(item => item.trim()).filter(item => item !== "") : [] ,
        bot_instructions: $('If1').first().json.body.data.bot_instructions
      }
    }
  }
];
